import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.4hJCcvDE.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/知识点_004-手游纹理格式详解.md","filePath":"blog/知识点_004-手游纹理格式详解.md","lastUpdated":1784835052000}'),l={name:"blog/知识点_004-手游纹理格式详解.md"};function o(n,e,_,s,h,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>PNG可以说是游戏和web经常用到的一种数据格式了,本人之前是对这个格式有些了解,但是没有系统的梳理过,今天跟人讨论在Unity里,图片用TGA还是PNG,发现自己对这个格式有些细节还是不太了解,就查了下资源梳理了一下 PS:最后讨论结果是用TGA比较好,理由是PS对PNG的支持不是很好.并且unity最终在设备上并不会直接使用该图片,最终打包都是要转成对应平台的压缩纹理的.</p><p>我们游戏之前为了还原一直用端游的16位RGBA5551纹理,iOS也是直接用的RGBA5551,然后最近美术用3DsMax渲染出图,给的都是32位RGBA8888的带渐变透明的纹理,本来其他地方倒是没有问题,但是最近发现半透明的阴影丢失了. 为了解决这个问题,只能对美术给的新图使用新的纹理格式,研究了一下PVRTC2,PVRTC4和RGBA4444的纹理格式,对比了一下效果,发现PVRTC4对于角色边缘的半透明部分过渡处理的比较好,而且占用小一半.但是美术觉得颜色信息丢失比较多. 所以最后还是用的RGBA4444.</p><h2 id="开坑待填" tabindex="-1">开坑待填 <a class="header-anchor" href="#开坑待填" aria-label="Permalink to &quot;开坑待填&quot;">​</a></h2><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Portable_Network_Graphics" target="_blank" rel="noreferrer">Portable Network Graphics - wikipedia</a></li><li><a href="http://www.alloyteam.com/2017/03/the-story-of-png-get-images-and-pixel-content/" target="_blank" rel="noreferrer">png 的故事：获取图片信息和像素内容</a></li><li><a href="https://medium.com/@duhroach/reducing-png-file-size-8473480d0476" target="_blank" rel="noreferrer">Reducing PNG file Size</a></li><li><a href="https://wlxklyh.github.io/2017/09/10/picture-texture/" target="_blank" rel="noreferrer">手游中的文件格式和纹理格式</a></li></ul><blockquote><p>未完待续</p></blockquote>',7)])])}const u=a(l,[["render",o]]);export{d as __pageData,u as default};
